import React, { useState, useEffect } from 'react';
import { BookOpen, Plus, MapPin, Calendar, Trash2, X, Save } from 'lucide-react';
import { supabase } from '../../services/supabaseClient';

function LogbookView() {
  const [entries, setEntries] = useState([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [loading, setLoading] = useState(true);

  // State för det nya inlägget
  const [newEntry, setNewEntry] = useState({
    title: '',
    content: '',
    location: ''
  });

  // Hämta alla loggboksinlägg från Supabase
  const fetchEntries = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('logbook')
      .select('*')
      .order('created_at', { ascending: false }); // Nyaste minnet först

    if (!error && data) {
      setEntries(data);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchEntries();
  }, []);

  // Spara ett nytt minne
  const handleAddEntry = async () => {
    if (newEntry.title.trim() === '' || newEntry.content.trim() === '') return;

    const today = new Date().toLocaleDateString('sv-SE');

    const { error } = await supabase
      .from('logbook')
      .insert([{ 
        title: newEntry.title, 
        content: newEntry.content, 
        location: newEntry.location || 'Okänd plats',
        date: today
      }]);

    if (!error) {
      setShowAddModal(false);
      setNewEntry({ title: '', content: '', location: '' });
      fetchEntries(); // Ladda om listan
    } else {
      alert("Kunde inte spara minnet: " + error.message);
    }
  };

  // Radera ett minne (bra att ha!)
  const handleDelete = async (id) => {
    if (window.confirm("Vill du verkligen radera detta minne?")) {
      const { error } = await supabase.from('logbook').delete().eq('id', id);
      if (!error) fetchEntries();
    }
  };

  return (
    <div style={{ padding: '20px' }} className="animate-fade-in">

      <header style={headerStyle}>
        <h1 style={titleStyle}>
          <BookOpen size={28} /> Loggboken
        </h1>
        <div style={countBadgeStyle}>{entries.length} minnen</div>
      </header>

      {/* LISTA MED MINNEN */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px', marginBottom: '100px' }}>
        {loading ? (
          <p style={statusTextStyle}>Hämtar dina minnen...</p>
        ) : entries.length === 0 ? (
          <div style={emptyStateStyle}>
            <p>Loggboken är tom.</p>
            <small>Dags att skapa nya minnen på vägen!</small>
          </div>
        ) : (
          entries.map((entry) => (
            <div key={entry.id} style={entryCardStyle}>
              <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                <h3 style={entryTitleStyle}>{entry.title}</h3>
                <button onClick={() => handleDelete(entry.id)} style={deleteBtnStyle}>
                  <Trash2 size={16} />
                </button>
              </div>

              <p style={entryContentStyle}>{entry.content}</p>

              <div style={entryFooterStyle}>
                <span style={infoItemStyle}><MapPin size={14} /> {entry.location}</span>
                <span style={infoItemStyle}><Calendar size={14} /> {entry.date}</span>
              </div>
            </div>
          ))
        )}
      </div>

      {/* FIXERAD KNAPP LÄNGST NER */}
      <button onClick={() => setShowAddModal(true)} style={floatingBtnStyle}>
        <Plus size={24} /> Skriv nytt minne
      </button>

      {/* MODAL FÖR NYTT INLÄGG */}
      {showAddModal && (
        <div style={overlayStyle} className="animate-fade-in">
          <div style={modalStyle}>
            <div style={modalHeaderStyle}>
              <h2 style={{ margin: 0, color: '#2D5A27' }}>Nytt minne</h2>
              <button onClick={() => setShowAddModal(false)} style={closeBtnStyle}><X /></button>
            </div>

            <input 
              type="text" 
              placeholder="Rubrik (t.ex. Solnedgång vid kusten)" 
              value={newEntry.title}
              onChange={(e) => setNewEntry({...newEntry, title: e.target.value})}
              style={inputStyle}
            />

            <input 
              type="text" 
              placeholder="Vart var ni? (t.ex. Varberg)" 
              value={newEntry.location}
              onChange={(e) => setNewEntry({...newEntry, location: e.target.value})}
              style={inputStyle}
            />

            <textarea 
              placeholder="Berätta om dagen..." 
              value={newEntry.content}
              onChange={(e) => setNewEntry({...newEntry, content: e.target.value})}
              style={{ ...inputStyle, height: '120px', resize: 'none' }}
            />

            <button onClick={handleAddEntry} style={saveBtnStyle}>
              <Save size={20} /> Spara i loggboken
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

// --- DESIGNMALLAR ---
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' };
const titleStyle = { fontSize: '24px', fontWeight: 'bold', color: '#2D5A27', margin: 0, display: 'flex', alignItems: 'center', gap: '10px' };
const countBadgeStyle = { backgroundColor: '#E8F5E9', padding: '5px 12px', borderRadius: '15px', color: '#2D5A27', fontSize: '12px', fontWeight: 'bold' };
const entryCardStyle = { backgroundColor: '#FFF', padding: '20px', borderRadius: '20px', boxShadow: '0 4px 15px rgba(0,0,0,0.05)', border: '1px solid #F0F0F0' };
const entryTitleStyle = { margin: '0 0 10px 0', fontSize: '18px', color: '#2D3436' };
const entryContentStyle = { color: '#636E72', lineHeight: '1.6', margin: '0 0 15px 0', fontSize: '15px' };
const entryFooterStyle = { display: 'flex', gap: '15px', borderTop: '1px solid #F5F2ED', paddingTop: '12px' };
const infoItemStyle = { display: 'flex', alignItems: 'center', gap: '5px', fontSize: '12px', color: '#95A5A6' };
const floatingBtnStyle = { position: 'fixed', bottom: '90px', right: '20px', backgroundColor: '#2D5A27', color: 'white', border: 'none', padding: '15px 25px', borderRadius: '30px', fontWeight: 'bold', boxShadow: '0 10px 25px rgba(45,90,39,0.3)', display: 'flex', alignItems: 'center', gap: '10px', zIndex: 100, cursor: 'pointer' };
const overlayStyle = { position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, backgroundColor: 'rgba(0,0,0,0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 1100, padding: '20px' };
const modalStyle = { backgroundColor: '#FFF', padding: '25px', borderRadius: '25px', width: '100%', maxWidth: '400px' };
const modalHeaderStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' };
const inputStyle = { width: '100%', padding: '15px', borderRadius: '12px', border: '2px solid #F5F2ED', marginBottom: '15px', fontSize: '16px', boxSizing: 'border-box', outline: 'none' };
const saveBtnStyle = { width: '100%', padding: '16px', backgroundColor: '#2D5A27', color: 'white', border: 'none', borderRadius: '15px', fontWeight: 'bold', fontSize: '16px', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '10px', cursor: 'pointer' };
const deleteBtnStyle = { background: 'none', border: 'none', color: '#FFEBEE', cursor: 'pointer', padding: '5px', color: '#E74C3C' };
const closeBtnStyle = { background: 'none', border: 'none', color: '#95A5A6', cursor: 'pointer' };
const statusTextStyle = { textAlign: 'center', color: '#95A5A6', fontStyle: 'italic', marginTop: '40px' };
const emptyStateStyle = { textAlign: 'center', padding: '60px 20px', color: '#95A5A6', backgroundColor: '#F9F9F9', borderRadius: '20px', border: '2px dashed #EEE' };

export default LogbookView;
